#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    long long n;    cin >> n;    vector<long long> a(n), b;    for (long long i = 0; i < n; i++) {        cin >> a[i];    }    b.push_back(a[0]);    for (long long i = 1; i < n; i++) {        if (a[i] >= a[i - 1]) {             b.push_back(a[i]);        }        else{            b.push_back(a[i]);            b.push_back(a[i]);        }    }    cout << b.size() << endl;    for (long long x : b) {        cout << x << " ";    }    cout << endl;               } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}